public display Qty rAFPostedQtyTotal()
{

    Qty  rAFPostedQtyTotal;
    ProdTable  prodTable;
    queryRun qrTotal;

    ProdParmReportFinished   prodParmReportFinished;
    FormDatasource     prodParmReportFinished_ds;
    //  prodParmReportFinished = element.dt;

    while select sum(PostedQty) from prodParmReportFinished where prodParmReportFinished.ParmId == this.ParmId
